import api from './api';

export default {
  /**
   * Login user
   * @param {Object} credentials - User credentials (username, password)
   * @returns {Promise} Promise containing the authentication result
   */
  login(credentials) {
    return api.post('/auth/signin', credentials);
  },
  
  /**
   * Register new user
   * @param {Object} userData - User registration data
   * @returns {Promise} Promise containing the registration result
   */
  register(userData) {
    return api.post('/auth/signup', userData);
  },
  
  /**
   * Check auth status
   * @returns {Promise} Promise containing the auth status
   */
  checkAuthStatus() {
    return api.get('/auth/check');
  },
  
  /**
   * Save user data to local storage
   * @param {Object} userData - User data to save
   */
  saveUser(userData) {
    localStorage.setItem('user', JSON.stringify(userData));
  },
  
  /**
   * Get user data from local storage
   * @returns {Object|null} User data or null if not found
   */
  getUser() {
    const userStr = localStorage.getItem('user');
    return userStr ? JSON.parse(userStr) : null;
  },
  
  /**
   * Remove user data from local storage (logout)
   */
  removeUser() {
    localStorage.removeItem('user');
  }
};
